#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int w[100010],v[100010],dp[100010],s,n,d;
signed main(void)
{
	s=read();n=read();d=read();
	FOR(i,1,d)
	{
		w[i]=read();v[i]=read();
	}
	FOR(i,1,n)
	{
		int m=s/1000;
		FOR(j,1,d)
		{
			FOR(k,w[j]/1000,m)
			{
				dp[k]=max(dp[k],dp[k-w[j]/1000]+v[j]);
			}
		}
		s+=dp[m];
		cl(dp);
	}
	write(s);
	return false;
}
